        AbstractAgentRequest agentRequest = (AbstractAgentRequest) request;
        ParamInfo paramInfo = new ParamInfo();
        paramInfo.setNamespaceId(agentRequest.getNamespaceId());
        paramInfo.setAgentName(agentRequest.getAgentName());
